SpecMeanTestRes <- function(circdat, indsym, mu0) {	n <- length(circdat)	t10bar <- trigonometric.moment(circdat, p=1, center=FALSE,control.circular=list(units="degrees"))	tbar <- atan2(t10bar$sin, t10bar$cos)	if (tbar < 0) {tbar <- tbar+2*pi}	Rbar <- rho.circular(circdat) ; Rbar2 <- Rbar*Rbar	t2bar <- trigonometric.moment(circdat, p=2, center=TRUE,control.circular=list(units="degrees"))	abar2 <- t2bar$cos ; bbar2 <- t2bar$sin	if (indsym == 1) {bbar2 <- 0}	div <- 2*n*Rbar2	mubc <- tbar+(bbar2/div) ; tbarstderr <- sqrt((1-abar2)/div)
	if (mubc > 2*pi) {mubc <- mubc-2*pi} else	if (mubc < 0) {mubc <- mubc+2*pi}	dist <- pi-abs(pi-abs(mubc-mu0)) ; z <- dist/tbarstderr	return(list(z, mubc))	}